function delay(ms) {
  return new Promise(resolve => {
    setTimeout(resolve, ms);
  });
}

// Test: mide el tiempo antes y después
const inicio = Date.now();
await delay(100);
const fin = Date.now();
const duracion = fin - inicio;

function ejecutarEnSecuencia(tareas) {
  const resultados = [];
  for (const tarea of tareas) {
    resultados.push(tarea());
  }
  return resultados;
}

const tareas = [
  () => 'tarea 1 lista',
  () => 'tarea 2 lista',
  () => 'tarea 3 lista'
];

const resultados = ejecutarEnSecuencia(tareas);
